#include <stdlib.h>

struct TreeNode {
   int val;
   struct TreeNode *left;
   struct TreeNode *right;
};

void recoverTree(struct TreeNode* root) {
   struct TreeNode* prev = NULL;
   struct TreeNode* first = NULL;
   struct TreeNode* second = NULL;

   while (root) {
      if (root->left == NULL) {
         if (prev && prev->val > root->val) {
            if (first == NULL) {
               first = prev;
            }
            second = root;
         }
         prev = root;
         root = root->right;
      } else {
         struct TreeNode* pre = root->left;
         while (pre->right && pre->right != root) {
            pre = pre->right;
         }
         if (pre->right == NULL) {
            pre->right = root;
            root = root->left;
         } else {
            pre->right = NULL;
            if (prev && prev->val > root->val) {
               if (first == NULL) {
                  first = prev;
               }
               second = root;
            }
            prev = root;
            root = root->right;
         }
      }
   }

   if (first && second) {
      int temp = first->val;
      first->val = second->val;
      second->val = temp;
   }
}

