   public void recoverTree(TreeNode root) {
      TreeNode prev = null;
      TreeNode first = null;
      TreeNode second = null;

      while (root != null) {
         if (root.left == null) {
            if (prev != null && prev.val > root.val) {
               if (first == null) {
                  first = prev;
               }
               second = root;
            }
            prev = root;
            root = root.right;
         } else {
            TreeNode pre = root.left;
            while (pre.right != null && pre.right != root) {
               pre = pre.right;
            }
            if (pre.right == null) {
               pre.right = root;
               root = root.left;
            } else {
               pre.right = null;
               if (prev != null && prev.val > root.val) {
                  if (first == null) {
                     first = prev;
                  }
                  second = root;
               }
               prev = root;
               root = root.right;
            }
         }
      }

